let hpos = document.querySelectorAll('a[href="admin.php?page=wc-orders"]')
let legacy = document.querySelectorAll('a[href="edit.php?post_type=shop_order"]')

if (hpos.length !== 0) {
    return "on"
}

if (legacy.length !== 0) {
    return "off"
}

function checkAdminNote(note) {
    const pattern = /Failure message is Your card was declined\.\. Notification ID is [0-9]+/;
    return pattern.test(note);
}

// Select all <p> elements within ul.order_notes > li > div > p
const notes = document.querySelectorAll('ul.order_notes > li > div > p');

// Check if any note matches the pattern
return Array.from(notes).some(note => checkAdminNote(note.textContent));

